import React, { useEffect, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI, thanhToanAPI } from '../services/api';
import { buildPhongAddress } from '../utils/location';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

const createManualSplitForm = () => ({
  tienPhong: '',
  tienDichVu: '',
  tienDien: '',
  tienNuoc: '',
  moTa: '',
});

export default function ChiTietPhong() {
  const { id } = useParams();
  const [phong, setPhong] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isOwner, setIsOwner] = useState(false);

  // Form chia tiền thủ công
  const [manualSplitForm, setManualSplitForm] = useState(createManualSplitForm());
  const [manualSplitLoading, setManualSplitLoading] = useState(false);

  useEffect(() => {
    phongAPI.layChiTiet(id)
      .then(r => {
        const phongData = r.data.data;
        setPhong(phongData);

        // Kiểm tra người dùng hiện tại có phải chủ phòng không
        const currentUserId = localStorage.getItem('userId'); // ← Thay đổi nếu bạn dùng Auth Context
        setIsOwner(phongData.maChuPhong === Number(currentUserId));
      })
      .catch(() => toast.error('Không tìm thấy phòng'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleChiaThuCong = async (event) => {
    event.preventDefault();

    if (!manualSplitForm.tienPhong || !manualSplitForm.tienDichVu || 
        !manualSplitForm.tienDien || !manualSplitForm.tienNuoc) {
      toast.error('Vui lòng nhập đầy đủ các khoản tiền');
      return;
    }

    setManualSplitLoading(true);
    try {
      await thanhToanAPI.chiaTienThuCong(id, {
        tienPhong: parseFloat(manualSplitForm.tienPhong || 0),
        tienDichVu: parseFloat(manualSplitForm.tienDichVu || 0),
        tienDien: parseFloat(manualSplitForm.tienDien || 0),
        tienNuoc: parseFloat(manualSplitForm.tienNuoc || 0),
        moTa: manualSplitForm.moTa.trim(),
      });

      toast.success('Đã tạo hóa đơn chia tiền thủ công thành công!');
      setManualSplitForm(createManualSplitForm()); // Reset form
    } catch (err) {
      toast.error(err.response?.data?.message || 'Chia tiền thủ công thất bại');
    } finally {
      setManualSplitLoading(false);
    }
  };

  if (loading) return <div className="spinner" />;

  if (!phong) {
    return (
      <div className="container page-wrapper">
        <div className="alert alert-danger">Không tìm thấy phòng.</div>
      </div>
    );
  }

  return (
    <div className="container page-wrapper">
      <div className="grid-2" style={{ alignItems: 'start' }}>
        {/* Card thông tin phòng */}
        <div className="card">
          <div className="card-body">
            <h1 style={{ fontSize: 26, fontWeight: 800 }}>{phong.title}</h1>
            <div style={{ fontSize: 28, fontWeight: 800, color: 'var(--primary)', margin: '10px 0' }}>
              {fmt(phong.giaTien)}/thang
            </div>
            <div style={{ color: 'var(--text-muted)', marginBottom: 16 }}>
              {buildPhongAddress(phong)}
            </div>

            <div className="grid-4" style={{ marginBottom: 20 }}>
              <div className="stat-card">
                <div className="stat-value" style={{ fontSize: 22 }}>{fmt(phong.tienDichVu)}</div>
                <div className="stat-label">Dịch vụ</div>
              </div>
              <div className="stat-card">
                <div className="stat-value" style={{ fontSize: 22 }}>{fmt(phong.tienDien)}</div>
                <div className="stat-label">Tiền điện</div>
              </div>
              <div className="stat-card">
                <div className="stat-value" style={{ fontSize: 22 }}>{fmt(phong.tienNuoc)}</div>
                <div className="stat-label">Tiền nước</div>
              </div>
              <div className="stat-card">
                <div className="stat-value">{phong.soNguoiToiDa - phong.soNguoiHienTai}</div>
                <div className="stat-label">Còn chỗ</div>
              </div>
            </div>

            <div style={{ display: 'flex', gap: 20, marginBottom: 20 }}>
              <div className="stat-card" style={{ flex: 1, padding: 16 }}>
                <div className="stat-value">{phong.soNguoiHienTai}</div>
                <div className="stat-label">Hiện tại</div>
              </div>
              <div className="stat-card" style={{ flex: 1, padding: 16 }}>
                <div className="stat-value">{phong.soNguoiToiDa}</div>
                <div className="stat-label">Tối đa</div>
              </div>
            </div>

            {phong.moTa && <p style={{ color: 'var(--text-muted)', lineHeight: 1.8 }}>{phong.moTa}</p>}
          </div>
        </div>

        {/* Card Thành viên */}
        <div className="card">
          <div className="card-header">Thành viên hiện tại</div>
          <div className="card-body">
            {/* Chủ phòng */}
            <Link
              to={`/nguoi-dung/${phong.maChuPhong}`}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 12,
                padding: '12px 0',
                borderBottom: '1px solid var(--border)',
                textDecoration: 'none',
              }}
            >
              <img
                src={phong.avatarChuPhong || `https://ui-avatars.com/api/?name=${encodeURIComponent(phong.tenChuPhong)}&background=12355B&color=fff&size=40`}
                className="avatar avatar-sm"
                alt=""
              />
              <div>
                <div style={{ fontWeight: 700 }}>{phong.tenChuPhong}</div>
                <span className="badge badge-info">Chủ phòng</span>
              </div>
            </Link>

            {/* Các thành viên khác */}
            {phong.danhSachThanhVien?.map(member => (
              <Link
                key={member.maNguoiDung}
                to={`/nguoi-dung/${member.maNguoiDung}`}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  padding: '12px 0',
                  borderBottom: '1px solid var(--border)',
                  textDecoration: 'none',
                }}
              >
                <img
                  src={member.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(member.hoTen)}&size=40`}
                  className="avatar avatar-sm"
                  alt=""
                />
                <div>
                  <div style={{ fontWeight: 600 }}>{member.hoTen}</div>
                  <span className="badge badge-secondary" style={{ opacity: 0.85, fontSize: '0.85em' }}>
                    Thành viên
                  </span>
                </div>
              </Link>
            ))}

            {phong.danhSachThanhVien?.length === 0 && (
              <p style={{ color: 'var(--text-muted)', fontStyle: 'italic', padding: '12px 0' }}>
                Phòng hiện chưa có thành viên nào khác.
              </p>
            )}
          </div>
        </div>
      </div>

      {/* ==================== PHẦN CHIA TIỀN THỦ CÔNG (Chỉ chủ phòng thấy) ==================== */}
      {isOwner && (
        <div className="card" style={{ marginTop: 28 }}>
          <div className="card-header">Chia tiền thủ công</div>
          <div className="card-body">
            <form onSubmit={handleChiaThuCong}>
              <div className="grid-2" style={{ marginBottom: 20 }}>
                <div className="form-group">
                  <label className="form-label">Mô tả (tùy chọn)</label>
                  <input
                    className="form-control"
                    value={manualSplitForm.moTa}
                    onChange={e => setManualSplitForm(prev => ({ ...prev, moTa: e.target.value }))}
                    placeholder="Ví dụ: Chia tiền tháng 5/2026"
                  />
                </div>
              </div>

              <div className="grid-4">
                <div className="form-group">
                  <label className="form-label">Tiền phòng</label>
                  <input
                    className="form-control"
                    type="number"
                    min="0"
                    value={manualSplitForm.tienPhong}
                    onChange={e => setManualSplitForm(prev => ({ ...prev, tienPhong: e.target.value }))}
                    required
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Tiền dịch vụ</label>
                  <input
                    className="form-control"
                    type="number"
                    min="0"
                    value={manualSplitForm.tienDichVu}
                    onChange={e => setManualSplitForm(prev => ({ ...prev, tienDichVu: e.target.value }))}
                    required
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Tiền điện</label>
                  <input
                    className="form-control"
                    type="number"
                    min="0"
                    value={manualSplitForm.tienDien}
                    onChange={e => setManualSplitForm(prev => ({ ...prev, tienDien: e.target.value }))}
                    required
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Tiền nước</label>
                  <input
                    className="form-control"
                    type="number"
                    min="0"
                    value={manualSplitForm.tienNuoc}
                    onChange={e => setManualSplitForm(prev => ({ ...prev, tienNuoc: e.target.value }))}
                    required
                  />
                </div>
              </div>

              <button
                type="submit"
                className="btn btn-primary"
                disabled={manualSplitLoading}
                style={{ marginTop: 16 }}
              >
                {manualSplitLoading ? 'Đang tạo hóa đơn...' : 'Tạo hóa đơn chia tiền thủ công'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
